// Extrai o JSON retornado pela OpenAI (vem dentro de choices[0].message.content)
const resp = $input.first().json;
let texto = '';
try {
  texto = resp.choices[0].message.content;
} catch (e) {
  texto = '{}';
}

texto = texto.replace(/```json/g, '').replace(/```/g, '').trim();

let avaliacao;
try {
  avaliacao = JSON.parse(texto);
} catch (e) {
  avaliacao = {};
}

// Defaults garantem que a página no Notion nunca quebra por campo faltando
const avaliacaoCompleta = {
  compatibilidade: 0,
  pontos_fortes: [],
  gaps: ['Erro ao interpretar resposta da IA'],
  vale_a_pena: false,
  resumo_empresa: '',
  senioridade_da_vaga: 'Nao especificado',
  tecnologias_encontradas: [],
  stack_ausente: [],
  localizacao_avaliada: '',
  idioma_requerido: '',
  exige_experiencia_previa: null,
  justificativa_nota: '',
  area_vaga: 'Dev',
  ...avaliacao
};

const vaga = $('Processar Uma Vaga por Vez').item.json;

console.log(`[IA] "${vaga.titulo}" (${vaga.empresa}) | score heurístico=${vaga.score_heuristico} | compatibilidade IA=${avaliacaoCompleta.compatibilidade}`);

return [{
  json: {
    ...vaga,
    ...avaliacaoCompleta
  }
}];
